#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_user_creation() {
        // Arrange: set up test data
        let name = "Alice";
        let email = "alice@example.com";

        // Act: perform the operation
        let user = User::new(name, email);

        // Assert: verify the result
        assert_eq!(user.name(), name);
        assert_eq!(user.email(), email);
        assert!(user.is_active());
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    mod creation {
        use super::*;

        #[test]
        fn creates_with_valid_data() {
            let result = Widget::new("test", 42);
            assert!(result.is_ok());
        }

        #[test]
        fn rejects_empty_name() {
            let result = Widget::new("", 42);
            assert!(result.is_err());
        }

        #[test]
        fn rejects_negative_value() {
            let result = Widget::new("test", -1);
            assert!(result.is_err());
        }
    }

    mod serialization {
        use super::*;

        #[test]
        fn round_trips_through_json() {
            let original = Widget::new("test", 42).unwrap();
            let json = serde_json::to_string(&original).unwrap();
            let parsed: Widget = serde_json::from_str(&json).unwrap();
            assert_eq!(original, parsed);
        }
    }
}

// Run all tests:
// cargo test

// Run tests matching a name:
// cargo test test_user

// Run tests in a specific module:
// cargo test tests::creation

// Show println! output (normally suppressed):
// cargo test -- --nocapture

// Run tests sequentially (not parallel):
// cargo test -- --test-threads=1

// Run only integration tests:
// cargo test --test integration_test

// Run only unit tests (skip integration):
// cargo test --lib

// Run ignored tests:
// cargo test -- --ignored

// List all tests without running:
// cargo test -- --list

